class Dog:
    def __init__(self, name, breed):
        self.name = name
        self.breed = breed

    def bark(self):
        print(f"{self.name} says: Woof!")

dog1 = Dog("Bella", "Labrador")
dog2 = Dog("Max", "Poodle")
dog1.bark()
dog2.bark()

class Dog:
    def bark():
        print("Woof!")

dog = Dog()
dog.bark()

